368→\begin{lemma}[{\cite[\href{https://stacks.math.columbia.edu/tag/096C}{Tag 096C}, first part]{stacks-project}}]
369→\label{thm:cartesian-profinite}
370→\uses{def:pi0-to-totally-disconnected}
371→\lean{ConnectedComponents.spectralSpace_of_isPullback,ConnectedComponents.lift_bijective_of_isPullback,ConnectedComponents.isHomeomorph_lift_of_isPullback}
372→\leanok
373→Let $X$ be a spectral space. Let
374→\[
375→\begin{tikzcd}
376→Y \arrow[r] \arrow[d] & T \arrow[d] \\
377→X \arrow[r] & \pi_0(X)
378→\end{tikzcd}
379→\]
380→be a cartesian diagram in the category of topological spaces with $T$ profinite. Then $Y$ is spectral and the canonical map $\pi_0(Y) \to T$ defined in \Cref{def:pi0-to-totally-disconnected} is an isomorphism.
381→\end{lemma}
382→
383→\begin{proof}
384→  \uses{thm:profinite-spectral,thm:pullback-spectral,thm:pi0-profinite,def:pi0-to-totally-disconnected,thm:pi0-to-totally-disconnected-injective}
385→  By \Cref{thm:profinite-spectral}, \(T\) is spectral. By \Cref{thm:pi0-profinite} \(\pi_0(X)\) is Hausdorff.
386→  By \Cref{thm:pullback-spectral}, \(Y\) is spectral.
387→  Let $Y \to \pi_0(Y) \to T$ be the canonical factorization in \Cref{def:pi0-to-totally-disconnected}. It is clear that $\pi_0(Y) \to T$ is surjective. The fibres of $Y \to T$ are homeomorphic to the fibres of $X \to \pi_0(X)$. Hence these fibres are connected. It follows that $\pi_0(Y) \to T$ is injective by \Cref{thm:pi0-to-totally-disconnected-injective}. We conclude that $\pi_0(Y) \to T$ is a homeomorphism since it is a bijective map from a quasi-compact space to a Hausdorff space by \verb`isHomeomorph_iff_continuous_bijective`.
388→\end{proof}
389→
390→The following pure algebraic lemma will be used in \Cref{thm:isom-of-identifies-local-rings-w-local-isom-pi0}.
391→
392→\begin{lemma}[{\cite[\href{https://stacks.math.columbia.edu/tag/00EA}{Tag 00EA}, (1) + (2)(a)]{stacks-project}}]
393→  \label{thm:localization-isom-of-going-down}
394→  \lean{Algebra.HasGoingDown.factor_bijective_of_subsingleton}
395→  \leanok
396→  Let $A \to B$ be a ring map which has going down. Let $\p \subset A$ be a prime ideal and let 
397→  $\q \subset B$ be a prime ideal lying over $\p$. Assume that and there is at most one prime
398→  of $B$ above every prime of $A$. Then the natural map $B_{\p B} \to B_{\q}$ is an isomorphism.
399→\end{lemma}
400→
401→\begin{proof}
402→  It suffices to show that all the elements of $B - \q$ are all invertible in $B_{\p B}$. Suppose the contrary, let $x \in B - \q$ be an element not invertible in $B_{\p B}$. We can find a prime ideal $\q' \subseteq \p B$ of $B$ containing $x$. By going down there exists a prime $\q'' \subseteq \q$ lying over $\p' = A \cap \q'$. By the uniqueness of primes lying over $\p'$ we see that $\q' = \q''$, which contradicts the fact that $x \notin \q$.
403→\end{proof}
404→
405→\begin{definition}[Local isomorphisms, {\cite[\href{https://stacks.math.columbia.edu/tag/096E}{Tag 096E} (1)]{stacks-project}}]
406→  \label{def:local-isomorphism}
407→  \lean{Algebra.IsLocalIso, RingHom.IsLocalIso}
408→  \leanok
409→  We say $A \to B$ is a \emph{local isomorphism} if for every prime $\mathfrak{q} \subset B$ there exists a $g \in B$, $g \notin \mathfrak{q}$ such that $A \to B_g$ induces an open immersion $\Spec (B_g) \to \Spec (A)$.
410→\end{definition}
411→
412→\begin{definition}[Identify local rings, {\cite[\href{https://stacks.math.columbia.edu/tag/096E}{Tag 096E} (2)]{stacks-project}}]
413→  A ring map $A \to B$ \emph{identifies local rings} if for every prime $\mathfrak{q} \subset B$ the canonical map $A_{\varphi^{-1}(\mathfrak{q})} \to B_{\mathfrak{q}}$ is an isomorphism.
414→  \label{def:identify-local-rings}
415→  \lean{RingHom.BijectiveOnStalks}
416→  \leanok
417→\end{definition}

